    t0 = t0 * t0 + f;
    t1 = t1 * t1 + f;
    t2 = t2 * t2 + f;
    t3 = t3 * t3 + f;
    t4 = t4 * t4 + f;
    t5 = t5 * t5 + f;
    t6 = t6 * t6 + f;
    t7 = t7 * t7 + f;
