#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    uchar is_leaf;
    uchar _pad0;
    uchar _pad1;
    uchar _pad2;
    int num_keys;
} knode;

__kernel void
findK(long maxheight,
      __global knode *knodes,
      long knodes_elem,
      __global record *records,
      __global long *currKnode,
      __global long *offset,
      __global int *keys,
      __global record *ans)
{
    const uint bid = get_group_id(0);
    const uint thid = get_local_id(0);
    const uint threadsPerBlock = get_local_size(0);

    __local long shared_currKnode;
    __local long shared_offset;

    if (thid == 0) {
        shared_currKnode = currKnode[bid];
        shared_offset = offset[bid];
    }
    barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);

    for (long i = 0; i < maxheight; i++) {
        long curr = shared_currKnode;
        int key = keys[bid];

        if ((knodes[curr].keys[thid] <= key) &&
            (knodes[curr].keys[thid + 1] > key)) {
            int index = knodes[curr].indices[thid];
            if ((long)index < knodes_elem) {
                shared_offset = (long)index;
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);

        if (thid == 0) {
            shared_currKnode = shared_offset;
            currKnode[bid] = shared_currKnode;
            offset[bid] = shared_offset;
        }

        barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);
    }

    long curr = shared_currKnode;
    if ((uint)thid < threadsPerBlock) {
        if (knodes[curr].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[curr].indices[thid]].value;
        }
    }
}

