__kernel void hotspot(int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - iteration * EXPAND_RATE;
    const int small_block_rows = BLOCK_SIZE - iteration * EXPAND_RATE;

    const int blkX = small_block_cols * bx - borderCols;
    const int blkY = small_block_rows * by - borderRows;

    const int xidx = blkX + tx;
    const int yidx = blkY + ty;

    const int valid = (xidx >= 0 && xidx < col && yidx >= 0 && yidx < row);

    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;
    const float Cap_1 = (step * 0.001f) / Cap;

    __local float temp0[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp1[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_local[BLOCK_SIZE][BLOCK_SIZE];

    if (valid) {
        const int index = yidx * col + xidx;
        temp0[ty][tx] = temp_src[index];
        power_local[ty][tx] = power[index];
    } else {
        temp0[ty][tx] = 0.0f;
        power_local[ty][tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int buf = 0;

    for (int i = 0; i < iteration; i++) {
        const int txmin = i + 1;
        const int txmax = BLOCK_SIZE - i - 2;
        const int tymin = i + 1;
        const int tymax = BLOCK_SIZE - i - 2;

        if (valid &&
            tx >= txmin && tx <= txmax &&
            ty >= tymin && ty <= tymax) {

            float tc, tn, ts, tw, te;

            if (buf == 0) {
                tc = temp0[ty][tx];
                tn = temp0[ty - 1][tx];
                ts = temp0[ty + 1][tx];
                tw = temp0[ty][tx - 1];
                te = temp0[ty][tx + 1];

                temp1[ty][tx] = compute_point(yidx, xidx, row, col,
                                              tc, tn, ts, tw, te,
                                              power_local[ty][tx],
                                              Cap_1, Rx_1, Ry_1, Rz_1);
            } else {
                tc = temp1[ty][tx];
                tn = temp1[ty - 1][tx];
                ts = temp1[ty + 1][tx];
                tw = temp1[ty][tx - 1];
                te = temp1[ty][tx + 1];

                temp0[ty][tx] = compute_point(yidx, xidx, row, col,
                                              tc, tn, ts, tw, te,
                                              power_local[ty][tx],
                                              Cap_1, Rx_1, Ry_1, Rz_1);
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        buf = 1 - buf;
    }

    if (valid &&
        tx >= borderCols && tx < BLOCK_SIZE - borderCols &&
        ty >= borderRows && ty < BLOCK_SIZE - borderRows) {
        const int index = yidx * col + xidx;
        temp_dst[index] = (buf == 0) ? temp0[ty][tx] : temp1[ty][tx];
    }
}

#define MAX_PD      (3.0e6f)
#define PRECISION   0.001f
#define AMB_TEMP    80.0f

__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      const int col,
                      const int row,
                      const int borderCols,
                      const int borderRows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    (void)borderCols;
    (void)borderRows;

    const float step_div_Cap = (step / 1000.0f) / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    for (int it = 0; it < iteration; ++it) {
        __global float *src = (it & 1) ? temp_dst : temp_src;
        __global float *dst = (it & 1) ? temp_src : temp_dst;

        for (int r = 0; r < row; ++r) {
            int base = r * col;
            for (int c = 0; c < col; ++c) {
                int idx = base + c;
                float center = src[idx];

                float horiz = 0.0f;
                float vert = 0.0f;

                if (c > 0)       horiz += src[idx - 1] - center;
                if (c < col - 1) horiz += src[idx + 1] - center;
                if (r > 0)       vert  += src[idx - col] - center;
                if (r < row - 1) vert  += src[idx + col] - center;

                float delta = step_div_Cap *
                              (power[idx] +
                               horiz * Rx_1 +
                               vert * Ry_1 +
                               (AMB_TEMP - center) * Rz_1);

                dst[idx] = center + delta;
            }
        }
    }

    if ((iteration & 1) == 0) {
        int size = row * col;
        for (int i = 0; i < size; ++i) {
            temp_dst[i] = temp_src[i];
        }
    }
}

