__kernel void
kernel_gpu_opencl(par_str par,
                  dim_str dim,
                  __global const box_str* box,
                  __global const FOUR_VECTOR* rv,
                  __global const fp* qv,
                  __global FOUR_VECTOR* fv)
{
	long l = (long)get_group_id(0);
	int tx = (int)get_local_id(0);
	int local_size = (int)get_local_size(0);

	if (l >= dim.number_boxes) {
		return;
	}

	fp alpha = par.alpha;
	fp a2 = (fp)2.0f * alpha * alpha;

	long first_i = box[l].offset;

	for (int i = tx; i < NUMBER_PAR_PER_BOX; i += local_size) {

		FOUR_VECTOR rA = rv[first_i + i];
		FOUR_VECTOR fA = fv[first_i + i];

		for (int k = 0; k < (1 + box[l].nn); k++) {

			int pointer;
			if (k == 0) {
