				pointer = box[l].nei[k - 1].number;
			}

			long first_j = box[pointer].offset;

			for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

				FOUR_VECTOR rB = rv[first_j + j];
				fp qB = qv[first_j + j];

				fp r2 = rA.v + rB.v - DOT(rA, rB);
				fp u2 = a2 * r2;
				fp vij = exp(-u2);
				fp fs = (fp)2.0f * vij;

				fp dx = rA.x - rB.x;
				fp dy = rA.y - rB.y;
				fp dz = rA.z - rB.z;

				fp fxij = fs * dx;
				fp fyij = fs * dy;
				fp fzij = fs * dz;

				fA.v += qB * vij;
				fA.x += qB * fxij;
				fA.y += qB * fyij;
				fA.z += qB * fzij;
			}
		}

		fv[first_i + i] = fA;
	}
}

