    k02 = k20/Kd02;
    k42 = 500;
    k24 = k42/Kd24;

    k0Boff = 0.0014;
    k0Bon = k0Boff/0.2;
    k2Boff = k0Boff/100;
    k2Bon = k0Bon;
    k4Boff = k2Boff;
    k4Bon = k0Bon;

    k20B = k20/100;
    k02B = k02;
    k42B = k42;
    k24B = k24;

    kbi = 2.2;
    kib = kbi/33.5e-3;
    kpp1 = 1.72;
    Kmpp1 = 11.5;
    kib2 = kib;
    kb2i = kib2*5;
    kb24 = k24;
    kb42 = k42*33.5e-3/5;
    kta = kbi/1000;
    kat = kib;
    kt42 = k42*33.5e-6/5;
    kt24 = k24;
    kat2 = kib;
    kt2a = kib*5;

    kcanCaoff = 1;
    kcanCaon = kcanCaoff/0.5;
