}

__kernel void kernel_gpu_opencl(fp timeinst,
                                __global fp *initvalu,
                                __global fp *finavalu,
                                __global fp *parameter,
                                __global fp *com)
{
    int gid = get_global_id(0);
    int i;

    fp JCaDyad;
    fp JCaSL;
    fp JCaCyt;

    if (gid != 0) {
        return;
    }

    ecc(timeinst,
        initvalu,
        0,
        parameter,
        0,
        finavalu);

    JCaDyad = cam(timeinst,
                  initvalu,
                  46,
                  parameter,
                  1,
                  finavalu,
                  initvalu[35]*1e3);

    JCaSL = cam(timeinst,
                initvalu,
                61,
                parameter,
                6,
                finavalu,
                initvalu[36]*1e3);

    JCaCyt = cam(timeinst,
                 initvalu,
                 76,
                 parameter,
                 11,
                 finavalu,
                 initvalu[37]*1e3);

    com[0] = JCaDyad;
    com[1] = JCaSL;
    com[2] = JCaCyt;

    for(i=0; i<EQUATIONS; i++){
        if (isnan(finavalu[i]) || isinf(finavalu[i])){
            finavalu[i] = 0.0001;
        }
    }
}

