__kernel void kernel_gpu_opencl(fp timeinst,
                                __global const fp *initvalu,
                                __global fp *finavalu,
                                __global const fp *parameter,
                                __global fp *com) {
    if (get_global_id(0) != 0) {
        return;
    }

    ecc(timeinst, initvalu, 0, parameter, 0, finavalu);

    com[0] = cam(timeinst, initvalu, 46, parameter, 1, finavalu, initvalu[35]*1e3f);
    com[1] = cam(timeinst, initvalu, 61, parameter, 6, finavalu, initvalu[36]*1e3f);
    com[2] = cam(timeinst, initvalu, 76, parameter, 11, finavalu, initvalu[37]*1e3f);
}

