__kernel void kernel_gpu_opencl(fp timeinst,
                                __global const fp *initvalu,
                                __global fp *finavalu,
                                __global const fp *parameter,
                                __global fp *com) {

    int gid = get_global_id(0);

    if (gid == 0) {
        ecc(timeinst,
            initvalu,
            0,
            parameter,
            0,
            finavalu);
    }
    else if (gid == 1) {
        fp CaDyad = initvalu[35]*1e3;
        com[0] = cam(timeinst,
                     initvalu,
                     46,
                     parameter,
                     1,
                     finavalu,
                     CaDyad);
    }
    else if (gid == 2) {
        fp CaSL = initvalu[36]*1e3;
        com[1] = cam(timeinst,
                     initvalu,
                     61,
                     parameter,
                     6,
                     finavalu,
                     CaSL);
    }
    else if (gid == 3) {
        fp CaCyt = initvalu[37]*1e3;
        com[2] = cam(timeinst,
                     initvalu,
                     76,
                     parameter,
                     11,
                     finavalu,
                     CaCyt);
    }
}

