inline RSComplex c_add(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r + B.r;
	C.i = A.i + B.i;
	return C;
}

inline RSComplex c_sub(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r - B.r;
	C.i = A.i - B.i;
	return C;
}

inline RSComplex c_mul_full(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r * B.r - A.i * B.i;
	C.i = A.r * B.i + A.i * B.r;
	return C;
}

inline RSComplex c_div_full(RSComplex A, RSComplex B)
{
	RSComplex C;
	double denom = B.r * B.r + B.i * B.i;
	C.r = (A.r * B.r + A.i * B.i) / denom;
	C.i = (A.i * B.r - A.r * B.i) / denom;
	return C;
}

inline double c_abs_full(RSComplex A)
{
	return sqrt(A.r * A.r + A.i * A.i);
}

inline double fast_exp(double x)
{
	x = 1.0 + x * 0.000244140625;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	return x;
}

inline RSComplex fast_cexp(RSComplex z)
{
	double x = z.r;
	double y = z.i;
	double t1 = fast_exp(x);
	RSComplex t4;
	t4.r = cos(y);
	t4.i = sin(y);
	RSComplex t5;
	t5.r = t1;
	t5.i = 0.0;
	return c_mul_full(t5, t4);
}

inline RSComplex fast_nuclear_W(RSComplex Z)
{
	if(c_abs_full(Z) < 6.0)
	{
		RSComplex prefactor = {0.0, 8.124330e+01};
		RSComplex t1 = {0.0, 12.0};
		RSComplex t2 = {12.0, 0.0};
		RSComplex imag1 = {0.0, 1.0};
		RSComplex one = {1.0, 0.0};

		RSComplex W = c_div_full(
			c_mul_full(imag1, c_sub(one, fast_cexp(c_mul_full(t1, Z)))),
			c_mul_full(t2, Z)
		);

		RSComplex sum = {0.0, 0.0};
		for(int n = 0; n < 10; n++)
		{
			RSComplex t3 = {fnw_neg_1n[n], 0.0};
			RSComplex top = c_sub(c_mul_full(t3, fast_cexp(c_mul_full(t1, Z))), one);
			RSComplex t4 = {fnw_denominator_left[n], 0.0};
			RSComplex t5 = {144.0, 0.0};
			RSComplex bot = c_sub(t4, c_mul_full(t5, c_mul_full(Z, Z)));
			RSComplex t6 = {fnw_an[n], 0.0};
			sum = c_add(sum, c_mul_full(t6, c_div_full(top, bot)));
		}
		W = c_add(W, c_mul_full(prefactor, c_mul_full(Z, sum)));
		return W;
	}
	else
	{
		RSComplex a = {0.512424224754768462984202823134979415014943561548661637413182, 0.0};
		RSComplex b = {0.275255128608410950901357962647054304017026259671664935783653, 0.0};
		RSComplex c = {0.051765358792987823963876628425793170829107067780337219430904, 0.0};
		RSComplex d = {2.724744871391589049098642037352945695982973740328335064216346, 0.0};
		RSComplex imag1 = {0.0, 1.0};
		RSComplex Z2 = c_mul_full(Z, Z);

		RSComplex W = c_mul_full(
			c_mul_full(Z, imag1),
			c_add(c_div_full(a, c_sub(Z2, b)), c_div_full(c, c_sub(Z2, d)))
		);

		return W;
	}
}

inline double LCG_random_double(ulong *seed)
{
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	const ulong mask = 0x7FFFFFFFFFFFFFFFUL;
	*seed = (a * (*seed) + c) & mask;
	return (double)(*seed) / 9223372036854775808.0;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong a_init = 2806196910506780709UL;
	const ulong c_init = 1UL;
	const ulong mask = 0x7FFFFFFFFFFFFFFFUL;

	ulong a = a_init;
	ulong c = c_init;
	ulong a_new = 1UL;
	ulong c_new = 0UL;

	n &= mask;

	while(n > 0UL)
	{
		if(n & 1UL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a *= a;
		n >>= 1UL;
	}

	return (a_new * seed + c_new) & mask;
}

inline int pick_mat(ulong *seed)
{
