static inline long grid_search(long n, double quarry, __global const double *A)
{
	long lowerLimit = 0;
	long upperLimit = n - 1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );
		if( A[examinationPoint] > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

static inline long grid_search_nuclide(long n, double quarry, __global const NuclideGridPoint *A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );
		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

static inline double LCG_random_double(ulong *seed)
{
	const ulong m = ((ulong)1 << 63);
	const ulong a = (ulong)2806196910506780709UL;
	const ulong c = (ulong)1;
	*seed = (a * (*seed) + c) % m;
	return (double)(*seed) / (double)m;
}

static inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong m = ((ulong)1 << 63);
	ulong a = (ulong)2806196910506780709UL;
	ulong c = (ulong)1;

	n = n % m;

	ulong a_new = (ulong)1;
	ulong c_new = (ulong)0;

	while(n > 0)
	{
		if(n & (ulong)1)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + (ulong)1);
		a *= a;
		n >>= 1;
	}

	return (a_new * seed + c_new) % m;
}

static inline int pick_mat(ulong *seed)
{
	double dist[12];
	dist[0]  = 0.140;
	dist[1]  = 0.052;
	dist[2]  = 0.275;
	dist[3]  = 0.134;
	dist[4]  = 0.154;
	dist[5]  = 0.064;
	dist[6]  = 0.066;
	dist[7]  = 0.055;
	dist[8]  = 0.008;
	dist[9]  = 0.015;
	dist[10] = 0.025;
	dist[11] = 0.013;

	double roll = LCG_random_double(seed);

	for( int i = 0; i < 12; i++ )
	{
		double running = 0.0;
		for( int j = i; j > 0; j-- )
			running += dist[j];
		if( roll < running )
			return i;
	}

	return 0;
}

static inline void calculate_micro_xs(
	double p_energy,
	int nuc,
