		if( idx == n_gridpoints - 1 )
			low = &nuclide_grids[(long)nuc * n_gridpoints + idx - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + idx];
	}
	else if( grid_type == UNIONIZED )
	{
		long base = idx * n_isotopes + (long)nuc;
		if( index_data[base] == n_gridpoints - 1 )
			low = &nuclide_grids[(long)nuc * n_gridpoints + index_data[base] - 1];
		else
			low = &nuclide_grids[(long)nuc * n_gridpoints + index_data[base]];
	}
	else
	{
		long base = idx * n_isotopes + (long)nuc;
		int u_low = index_data[base];

		int u_high;
		if( idx == (long)hash_bins - 1 )
			u_high = (int)n_gridpoints - 1;
		else
			u_high = index_data[((idx + 1) * n_isotopes) + (long)nuc] + 1;

		double e_low  = nuclide_grids[(long)nuc * n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[(long)nuc * n_gridpoints + u_high].energy;
		int lower;
		if( p_energy <= e_low )
			lower = 0;
		else if( p_energy >= e_high )
