__constant double material_dist[12] = {
	0.140, 0.052, 0.275, 0.134, 0.154, 0.064,
	0.066, 0.055, 0.008, 0.015, 0.025, 0.013
};

inline long grid_search(long n, double quarry, __global const double *A)
{
	long lowerLimit = 0;
	long upperLimit = n - 1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while (1 < length)
	{
		examinationPoint = lowerLimit + (length / 2);
		if (A[examinationPoint] > quarry)
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

inline long grid_search_nuclide(long n, double quarry, __global const NuclideGridPoint *A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while (length > 1)
	{
		examinationPoint = lowerLimit + (length / 2);
		if (quarry < A[examinationPoint].energy)
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

inline double LCG_random_double(ulong *seed)
{
	const ulong m = ((ulong)1) << 63;
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	*seed = (a * (*seed) + c) % m;
	return (double)(*seed) / (double)m;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong m = ((ulong)1) << 63;
	ulong a = 2806196910506780709UL;
	ulong c = 1UL;

	n = n % m;

	ulong a_new = 1UL;
	ulong c_new = 0UL;

	while (0 < n)
	{
		if (n & 1UL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a *= a;
		n >>= 1;
	}

	return (a_new * seed + c_new) % m;
}

inline int pick_mat(ulong *seed)
{
	double roll = LCG_random_double(seed);

	for (int i = 0; i < 12; i++)
	{
		double running = 0.0;
		for (int j = i; j > 0; j--)
			running += material_dist[j];
		if (running > roll)
			return i;
	}

	return 0;
}

inline void calculate_micro_xs(
	double p_energy,
	int nuc,
	long n_isotopes,
	long n_gridpoints,
	__global const double *egrid,
	__global const int *index_data,
	__global const NuclideGridPoint *nuclide_grids,
	long idx,
	double *xs_vector,
	int grid_type,
	int hash_bins)
{
	double f;
	long low_idx;
	long base = ((long)nuc) * n_gridpoints;

	if (grid_type == NUCLIDE)
	{
		idx = grid_search_nuclide(n_gridpoints, p_energy, nuclide_grids + base, 0, n_gridpoints - 1);

		if (idx == n_gridpoints - 1)
			low_idx = idx - 1;
		else
			low_idx = idx;
	}
	else if (grid_type == UNIONIZED)
	{
		long mapped = (long)index_data[idx * n_isotopes + nuc];

		if (mapped == n_gridpoints - 1)
